/// liter-llm-backed NER backend.
#[derive(Clone)]
#[napi(js_name = "LlmBackend")]
pub struct JsLlmBackend {
    inner: Arc<xberg::LlmBackend>,
}

#[napi]
impl JsLlmBackend {
    #[allow(clippy::missing_errors_doc)]
    #[napi]
    pub async fn detect(&self, text: String, categories: Vec<JsEntityCategory>) -> Result<Vec<JsEntity>> {
        let categories_json = serde_json::to_string(&categories)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        let categories_core: Vec<xberg::EntityCategory> = serde_json::from_str(&categories_json)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        let result = self
            .inner
            .detect(&text, &categories_core)
            .await
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        Ok(result.into_iter().map(Into::into).collect())
    }

    #[allow(clippy::missing_errors_doc)]
    #[napi(js_name = "detectWithCustom")]
    pub async fn detect_with_custom(
        &self,
        text: String,
        categories: Vec<JsEntityCategory>,
        custom_labels: Vec<String>,
    ) -> Result<Vec<JsEntity>> {
        let categories_json = serde_json::to_string(&categories)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        let categories_core: Vec<xberg::EntityCategory> = serde_json::from_str(&categories_json)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        let result = self
            .inner
            .detect_with_custom(&text, &categories_core, &custom_labels)
            .await
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        Ok(result.into_iter().map(Into::into).collect())
    }

    /// Create a new LLM-backed NER backend with the given LLM configuration.
    #[napi]
    pub fn new(config: JsLlmConfig) -> JsLlmBackend {
        Self {
            inner: Arc::new(xberg::LlmBackend::new(config.into())),
        }
    }
}

