/// Extract content from a single bytes or URI input.
#[allow(clippy::missing_errors_doc)]
#[napi]
pub async fn extract(input: Option<JsExtractInput>, config: Option<JsExtractionConfig>) -> Result<JsExtractionOutput> {
    let input_core: xberg::ExtractInput = input.unwrap_or_default().into();

    let config_core: xberg::ExtractionConfig = config.unwrap_or_default().into();

    let result = xberg::extract(input_core, &config_core)
        .await
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    Ok(result.into())
}

/// Extract content from multiple bytes or URI inputs.
