/// Wrapper that bridges a foreign JavaScript object to a Rust trait.
///
/// Holds the JS object via a persistent napi reference (`ObjectRef`) rather than
/// a borrowed `Object` transmuted to `'static`. The reference is released in
/// `dispose()` (and defensively in `Drop`) so the outstanding handle no longer
/// pins the libuv event loop, letting Node/worker threads exit cleanly.
pub struct JsOcrBackendBridge {
    env: napi::sys::napi_env,
    obj_ref: std::sync::Mutex<Option<napi::bindgen_prelude::ObjectRef<false>>>,
    cached_name: String,
    cancellation_token: std::sync::Arc<tokio_util::sync::CancellationToken>,
}

impl std::fmt::Debug for JsOcrBackendBridge {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "JsOcrBackendBridge")
    }
}

impl JsOcrBackendBridge {
    /// Create a new bridge wrapping a NAPI Object.
    ///
    /// Validates that the object provides all required methods.
    pub fn new(js_obj: napi::bindgen_prelude::Object<'_>) -> napi::Result<Self> {
        if !js_obj.has_named_property("processImage").unwrap_or(false)
            && !js_obj.has_named_property("process_image").unwrap_or(false)
        {
            return Err(napi::Error::new(
                napi::Status::GenericFailure,
                format!("Object missing required method: {}", "processImage"),
            ));
        }
        if !js_obj.has_named_property("supportsLanguage").unwrap_or(false)
            && !js_obj.has_named_property("supports_language").unwrap_or(false)
        {
            return Err(napi::Error::new(
                napi::Status::GenericFailure,
                format!("Object missing required method: {}", "supportsLanguage"),
            ));
        }
        if !js_obj.has_named_property("backendType").unwrap_or(false)
            && !js_obj.has_named_property("backend_type").unwrap_or(false)
        {
            return Err(napi::Error::new(
                napi::Status::GenericFailure,
                format!("Object missing required method: {}", "backendType"),
            ));
        }
        if !js_obj.has_named_property("name").unwrap_or(false) {
            return Err(napi::Error::new(
                napi::Status::GenericFailure,
                "Object missing required method: name".to_string(),
            ));
        } // Cache the plugin name while the borrowed object is still in scope. `name`
        // may be either a string property or a zero-arg function returning a string
        // (the trait method form). Try the function first, then fall back to a
        // string property.
        let cached_name = js_obj
            .get_named_property::<napi::bindgen_prelude::Function<(), String>>("name")
            .and_then(|f| f.call(()))
            .or_else(|_| js_obj.get_named_property::<String>("name"))
            .map_err(|e| {
                napi::Error::new(
                    napi::Status::GenericFailure,
                    format!("Object missing required method: name ({e})"),
                )
            })?;
        // Capture the raw napi_env that owns the object. It is stable for the
        // lifetime of the Node process and is used to reconstruct an `Env` when
        // materialising the object or building context arguments.
        // SAFETY: `Object<'_>` is laid out as 3 pointer-sized words whose first
        // word is the owning napi_env.
        let env = unsafe {
            let raw: [*mut std::ffi::c_void; 3] = std::mem::transmute_copy(&js_obj);
            raw[0] as napi::sys::napi_env
        };
        // Hold the JS object via a persistent napi reference instead of a borrowed
        // `Object` transmuted to `'static`. The reference keeps the value alive
        // across handle scopes and, crucially, is released in `dispose()`/`Drop`
        // so it no longer pins the event loop.
        let obj_ref = js_obj.create_ref::<false>()?;

        Ok(Self {
            env,
            obj_ref: std::sync::Mutex::new(Some(obj_ref)),
            cached_name,
            cancellation_token: std::sync::Arc::new(tokio_util::sync::CancellationToken::new()),
        })
    }

    /// Materialise a live `Object` from the persistent reference.
    ///
    /// The returned object is tied to the provided `Env` and kept alive by the
    /// underlying napi reference for the duration of the current event-loop turn.
    /// Returns an error once the reference has been released (after `dispose()`).
    fn obj<'env>(&self, env: &'env napi::Env) -> napi::Result<napi::bindgen_prelude::Object<'env>> {
        let guard = self.obj_ref.lock().unwrap_or_else(|e| e.into_inner());
        match guard.as_ref() {
            Some(obj_ref) => obj_ref.get_value(env),
            None => Err(napi::Error::new(
                napi::Status::GenericFailure,
                format!("Plugin '{}' object has been disposed", self.cached_name),
            )),
        }
    }

    /// Release the persistent reference, unpinning the event loop.
    ///
    /// Idempotent: safe to call multiple times. After disposal the bridge can no
    /// longer invoke the JS object.
    fn release_ref(&self) {
        if let Ok(mut guard) = self.obj_ref.lock() {
            if let Some(obj_ref) = guard.take() {
                let env = napi::Env::from_raw(self.env);
                let _ = obj_ref.unref(&env);
            }
        }
    }

    /// Clean up TSFN callbacks and release the event loop.
    pub async fn dispose(&self) -> napi::Result<()> {
        self.cancellation_token.cancel();
        self.release_ref();
        Ok(())
    }

    /// Extract napi::Env from the captured raw env pointer.
    fn env(&self) -> napi::Env {
        napi::Env::from_raw(self.env)
    }
}

impl Drop for JsOcrBackendBridge {
    fn drop(&mut self) {
        // Defensive release in case `dispose()` was never called. Releases the
        // napi reference so the JS object can be collected and the event loop is
        // no longer pinned by this bridge.
        self.release_ref();
    }
}

// SAFETY: The bridge is created from a NAPI Object that is pinned to the
// Node.js event loop thread. All napi access occurs on that thread; the stored
// reference (`ObjectRef`) is only dereferenced while reconstructing an `Env` for
// that same thread. Send+Sync are required by the Plugin trait but the bridge is
// never actually moved across threads.
unsafe impl Send for JsOcrBackendBridge {}
unsafe impl Sync for JsOcrBackendBridge {}

impl xberg::plugins::Plugin for JsOcrBackendBridge {
    fn name(&self) -> &str {
        &self.cached_name
    }

    fn version(&self) -> String {
        let __env = self.env();
        let __obj = match self.obj(&__env) {
            Ok(o) => o,
            Err(_) => return Default::default(),
        };
        let func: napi::bindgen_prelude::Function<(), napi::bindgen_prelude::Unknown> = match __obj
            .get_named_property("version")
            .or_else(|_| __obj.get_named_property("version"))
        {
            Ok(f) => f,
            Err(_) => return Default::default(),
        };

        let result = func.call(());

        match result {
            Err(_) => Default::default(),
            Ok(val) => {
                // Convert JS value to Rust type via string coercion
                let s = val
                    .coerce_to_string()
                    .and_then(|s| s.into_utf8())
                    .and_then(|s| s.into_owned())
                    .unwrap_or_default();
                match s.as_str() {
                    "" | "null" => Default::default(),
                    _ => serde_json::from_str::<_>(&s).unwrap_or_default(),
                }
            }
        }
    }

    fn initialize(&self) -> std::result::Result<(), xberg::XbergError> {
        let __env = self.env();
        let __obj = match self.obj(&__env) {
            Ok(o) => o,
            // Object disposed/unavailable — treat like a missing method (no-op default).
            Err(_) => return Ok(()),
        };
        let func: napi::bindgen_prelude::Function<(), napi::bindgen_prelude::Unknown> = match __obj
            .get_named_property("initialize")
            .or_else(|_| __obj.get_named_property("initialize"))
        {
            Ok(f) => f,
            // Method has a default impl on the Rust trait — treat missing JS property as a no-op
            // (the foreign object opted out of overriding it).
            Err(_) => return Ok(()),
        };

        let result = func.call(());

        match result {
            Err(e) => Err(xberg::XbergError::Other(format!(
                "Plugin '{}' method 'initialize' failed: {}",
                self.cached_name, e
            ))),
            Ok(_) => Ok(()),
        }
    }

    fn shutdown(&self) -> std::result::Result<(), xberg::XbergError> {
        let __env = self.env();
        let __obj = match self.obj(&__env) {
            Ok(o) => o,
            // Object disposed/unavailable — treat like a missing method (no-op default).
            Err(_) => return Ok(()),
        };
        let func: napi::bindgen_prelude::Function<(), napi::bindgen_prelude::Unknown> = match __obj
            .get_named_property("shutdown")
            .or_else(|_| __obj.get_named_property("shutdown"))
        {
            Ok(f) => f,
            // Method has a default impl on the Rust trait — treat missing JS property as a no-op
            // (the foreign object opted out of overriding it).
            Err(_) => return Ok(()),
        };

        let result = func.call(());

        match result {
            Err(e) => Err(xberg::XbergError::Other(format!(
                "Plugin '{}' method 'shutdown' failed: {}",
                self.cached_name, e
            ))),
            Ok(_) => Ok(()),
        }
    }
}

#[async_trait::async_trait]
impl xberg::OcrBackend for JsOcrBackendBridge {
    async fn process_image(
        &self,
        image_bytes: &[u8],
        config: &xberg::OcrConfig,
    ) -> std::result::Result<xberg::ExtractionResult, xberg::XbergError> {
        let cached_name = self.cached_name.clone();
        let __env = self.env();

        let __obj = match self.obj(&__env) {
            Ok(o) => o,
            Err(e) => {
                return Err(xberg::XbergError::Other(format!(
                    "Method '{}' not found on bridge object: {}",
                    cached_name, e
                )));
            }
        };
        let func: napi::bindgen_prelude::Function<
            napi::bindgen_prelude::FnArgs<(napi::bindgen_prelude::Unknown, napi::bindgen_prelude::Unknown)>,
            napi::bindgen_prelude::Unknown,
        > = match __obj
            .get_named_property("processImage")
            .or_else(|_| __obj.get_named_property("process_image"))
        {
            Ok(f) => f,
            Err(e) => {
                return Err(xberg::XbergError::Other(format!(
                    "Method '{}' not found on bridge object: {}",
                    cached_name, e
                )));
            }
        };

        let result = func.call(napi::bindgen_prelude::FnArgs::from((
            match self.env().create_string(&format!("{:?}", image_bytes)) {
                Ok(s) => s.to_unknown(),
                Err(_) => unsafe {
                    let r = napi::bindgen_prelude::ToNapiValue::to_napi_value(
                        self.env().raw(),
                        napi::bindgen_prelude::Null,
                    )
                    .unwrap_or(std::ptr::null_mut());
                    napi::bindgen_prelude::Unknown::from_raw_unchecked(self.env().raw(), r)
                },
            },
            unsafe {
                let r = napi::bindgen_prelude::ToNapiValue::to_napi_value(
                    self.env().raw(),
                    JsOcrConfig::from((*config).clone()),
                )
                .unwrap_or(std::ptr::null_mut());
                napi::bindgen_prelude::Unknown::from_raw_unchecked(self.env().raw(), r)
            },
        )));

        match result {
            Err(e) => Err(xberg::XbergError::Other(format!(
                "Plugin '{}' method 'process_image' failed: {}",
                cached_name, e
            ))),
            Ok(val) => {
                // Convert JS value to Rust type via string coercion
                let s = val
                    .coerce_to_string()
                    .and_then(|s| s.into_utf8())
                    .and_then(|s| s.into_owned())
                    .map_err(|e| {
                        xberg::XbergError::Other(format!(
                            "Failed to extract return value from method 'process_image': {}",
                            e
                        ))
                    })?;
                // null/empty is a protocol error for Result-returning methods: the JS
                // implementation must always return a serialisable value, never null.
                // Avoid requiring Default on the return type (excluded types like
                // InternalDocument do not implement Default).
                match s.as_str() {
                    "" | "null" => Err(xberg::XbergError::Other(
                        "Failed to parse return value for method 'process_image'".to_string(),
                    )),
                    _ => serde_json::from_str::<_>(&s).map_err(|_| {
                        xberg::XbergError::Other("Failed to parse return value for method 'process_image'".to_string())
                    }),
                }
            }
        }
    }

    fn supports_language(&self, lang: &str) -> bool {
        let __env = self.env();
        let __obj = match self.obj(&__env) {
            Ok(o) => o,
            Err(_) => return Default::default(),
        };
        let func: napi::bindgen_prelude::Function<
            napi::bindgen_prelude::FnArgs<(napi::bindgen_prelude::Unknown,)>,
            napi::bindgen_prelude::Unknown,
        > = match __obj
            .get_named_property("supportsLanguage")
            .or_else(|_| __obj.get_named_property("supports_language"))
        {
            Ok(f) => f,
            Err(_) => return Default::default(),
        };

        let result = func.call(napi::bindgen_prelude::FnArgs::from((
            match self.env().create_string(lang) {
                Ok(s) => s.to_unknown(),
                Err(_) => unsafe {
                    let r = napi::bindgen_prelude::ToNapiValue::to_napi_value(
                        self.env().raw(),
                        napi::bindgen_prelude::Null,
                    )
                    .unwrap_or(std::ptr::null_mut());
                    napi::bindgen_prelude::Unknown::from_raw_unchecked(self.env().raw(), r)
                },
            },
        )));

        match result {
            Err(_) => Default::default(),
            Ok(val) => {
                // Convert JS value to Rust type via string coercion
                let s = val
                    .coerce_to_string()
                    .and_then(|s| s.into_utf8())
                    .and_then(|s| s.into_owned())
                    .unwrap_or_default();
                match s.as_str() {
                    "" | "null" => Default::default(),
                    _ => serde_json::from_str::<_>(&s).unwrap_or_default(),
                }
            }
        }
    }

    fn backend_type(&self) -> xberg::OcrBackendType {
        let __env = self.env();
        let __obj = match self.obj(&__env) {
            Ok(o) => o,
            Err(_) => return Default::default(),
        };
        let func: napi::bindgen_prelude::Function<(), napi::bindgen_prelude::Unknown> = match __obj
            .get_named_property("backendType")
            .or_else(|_| __obj.get_named_property("backend_type"))
        {
            Ok(f) => f,
            Err(_) => return Default::default(),
        };

        let result = func.call(());

        match result {
            Err(_) => Default::default(),
            Ok(val) => {
                // Convert JS value to Rust type via string coercion
                let s = val
                    .coerce_to_string()
                    .and_then(|s| s.into_utf8())
                    .and_then(|s| s.into_owned())
                    .unwrap_or_default();
                match s.as_str() {
                    "" | "null" => Default::default(),
                    _ => serde_json::from_str::<_>(&s).unwrap_or_default(),
                }
            }
        }
    }
}

#[napi]
pub fn register_ocr_backend(obj: napi::bindgen_prelude::Object) -> napi::Result<()> {
    let bridge = JsOcrBackendBridge::new(obj)?;
    let arc: Arc<dyn xberg::OcrBackend> = Arc::new(bridge);

    let registry = xberg::plugins::registry::get_ocr_backend_registry();
    let mut registry = registry.write();
    registry.register(arc).map_err(|e| {
        napi::Error::new(
            napi::Status::GenericFailure,
            format!("Failed to register backend: {}", e),
        )
    })
}

