#[async_trait::async_trait]
impl xberg::RerankerBackend for JsRerankerBackendBridge {
    async fn rerank(&self, query: String, documents: Vec<String>) -> std::result::Result<Vec<f32>, xberg::XbergError> {
        let cached_name = self.cached_name.clone();
        let __env = self.env();

        let __obj = match self.obj(&__env) {
            Ok(o) => o,
            Err(e) => {
                return Err(xberg::XbergError::Other(format!(
                    "Method '{}' not found on bridge object: {}",
                    cached_name, e
                )));
            }
        };
        let func: napi::bindgen_prelude::Function<
            napi::bindgen_prelude::FnArgs<(napi::bindgen_prelude::Unknown, napi::bindgen_prelude::Unknown)>,
            napi::bindgen_prelude::Unknown,
        > = match __obj
            .get_named_property("rerank")
            .or_else(|_| __obj.get_named_property("rerank"))
        {
            Ok(f) => f,
            Err(e) => {
                return Err(xberg::XbergError::Other(format!(
                    "Method '{}' not found on bridge object: {}",
                    cached_name, e
                )));
            }
        };

        let result = func.call(napi::bindgen_prelude::FnArgs::from((
            match self.env().create_string(query.as_str()) {
                Ok(s) => s.to_unknown(),
                Err(_) => unsafe {
                    let r = napi::bindgen_prelude::ToNapiValue::to_napi_value(
                        self.env().raw(),
                        napi::bindgen_prelude::Null,
                    )
                    .unwrap_or(std::ptr::null_mut());
                    napi::bindgen_prelude::Unknown::from_raw_unchecked(self.env().raw(), r)
                },
            },
            match self.env().create_string(&format!("{:?}", documents)) {
                Ok(s) => s.to_unknown(),
                Err(_) => unsafe {
                    let r = napi::bindgen_prelude::ToNapiValue::to_napi_value(
                        self.env().raw(),
                        napi::bindgen_prelude::Null,
                    )
                    .unwrap_or(std::ptr::null_mut());
                    napi::bindgen_prelude::Unknown::from_raw_unchecked(self.env().raw(), r)
                },
            },
        )));

        match result {
            Err(e) => Err(xberg::XbergError::Other(format!(
                "Plugin '{}' method 'rerank' failed: {}",
                cached_name, e
            ))),
            Ok(val) => {
                // Convert JS value to Rust type via string coercion
                let s = val
                    .coerce_to_string()
                    .and_then(|s| s.into_utf8())
                    .and_then(|s| s.into_owned())
                    .map_err(|e| {
                        xberg::XbergError::Other(format!("Failed to extract return value from method 'rerank': {}", e))
                    })?;
                // null/empty is a protocol error for Result-returning methods: the JS
                // implementation must always return a serialisable value, never null.
                // Avoid requiring Default on the return type (excluded types like
                // InternalDocument do not implement Default).
                match s.as_str() {
                    "" | "null" => Err(xberg::XbergError::Other(
                        "Failed to parse return value for method 'rerank'".to_string(),
                    )),
                    _ => serde_json::from_str::<_>(&s).map_err(|_| {
                        xberg::XbergError::Other("Failed to parse return value for method 'rerank'".to_string())
                    }),
                }
            }
        }
    }
}

#[napi]
pub fn register_reranker_backend(obj: napi::bindgen_prelude::Object) -> napi::Result<()> {
    let bridge = JsRerankerBackendBridge::new(obj)?;
    let arc: Arc<dyn xberg::RerankerBackend> = Arc::new(bridge);

    let registry = xberg::plugins::registry::get_reranker_backend_registry();
    let mut registry = registry.write();
    registry.register(arc).map_err(|e| {
        napi::Error::new(
            napi::Status::GenericFailure,
            format!("Failed to register backend: {}", e),
        )
    })
}

#[napi(js_name = "unregisterRerankerBackend")]
pub fn _alef_unregister_reranker_backend(name: String) -> napi::Result<()> {
    xberg::plugins::reranker_backend::unregister_reranker_backend(&name)
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, format!("{}", e)))
}

#[napi(js_name = "clearRerankerBackends")]
pub fn _alef_clear_reranker_backends() -> napi::Result<()> {
    xberg::plugins::reranker_backend::clear_reranker_backends()
        .map_err(|e| napi::Error::new(napi::Status::GenericFailure, format!("{}", e)))
}

