impl From<JsChunkingReason> for xberg::ChunkingReason {
    fn from(val: JsChunkingReason) -> Self {
        match val.type_tag.as_str() {
            "largefile" => Self::LargeFile {
                size_bytes: val.size_bytes.map(|v| v as u64).unwrap_or_default(),
                threshold_bytes: val.threshold_bytes.map(|v| v as u64).unwrap_or_default(),
            },
            "manypages" => Self::ManyPages {
                page_count: val.page_count.unwrap_or_default(),
                threshold: val.threshold.unwrap_or_default(),
            },
            "ocrrequired" => Self::OcrRequired {
                page_count: val.page_count.unwrap_or_default(),
                force_ocr: val.force_ocr.unwrap_or_default(),
            },
            "largeandmanypages" => Self::LargeAndManyPages {
                size_bytes: val.size_bytes.map(|v| v as u64).unwrap_or_default(),
                page_count: val.page_count.unwrap_or_default(),
            },
            _ => Self::LargeFile {
                size_bytes: Default::default(),
                threshold_bytes: Default::default(),
            },
        }
    }
}

